var suggestions=document.getElementById("suggestions"),search=document.getElementById("search");search!==null&&document.addEventListener("keydown",inputFocus);function inputFocus(e){e.ctrlKey&&e.key==="/"&&(e.preventDefault(),search.focus()),e.key==="Escape"&&(search.blur(),suggestions.classList.add("d-none"))}document.addEventListener("click",function(e){var t=suggestions.contains(e.target);t||suggestions.classList.add("d-none")}),document.addEventListener("keydown",suggestionFocus);function suggestionFocus(n){const s=suggestions.classList.contains("d-none");if(s)return;const e=[...suggestions.querySelectorAll("a")];if(e.length===0)return;const t=e.indexOf(document.activeElement);if(n.key==="ArrowUp"){n.preventDefault();const s=t>0?t-1:0;e[s].focus()}else if(n.key==="ArrowDown"){n.preventDefault();const s=t+1<e.length?t+1:t;e[s].focus()}}(function(){var e=new FlexSearch.Document({tokenize:"forward",cache:100,document:{id:"id",store:["href","title","description"],index:["title","description","content"]}});e.add({id:0,href:"/docs/intro/",title:"Introducción",description:"Equilaterus WIKI starts here",content:""}),e.add({id:1,href:"/blog/curiosidad-asombro/",title:"Sobre el asombro y la curiosidad",description:'\\"(...)Ahí es donde está la mano del mediocre, que intenta recortarle a los demás la vida y decirles por donde tienen que ir. Negarse a que la realidad es proceso e insistir en que la realidad es definición y dogma\\" -Antonio Escohotado.',content:" \u0026ldquo;El pensamiento corrompe el lenguaje y el lenguaje también puede corromper el pensamiento\u0026rdquo; -George Orwell.\n Consciente que una introducción provieniente de una mente prosaica como la mía no sería más que un obstáculo para avanzar en el asunto que nos atañe, me limitaré a dejar que las palabras del maestro Escohotado resuenen en el alma.\n   Duración 58 segundos. Transcripción:\n \u0026ldquo;Tengo que llamar la atención hacia la verdadera dictadura que ahora estamos padeciendo, por ejemplo, en nombre de una academia de la lengua que pretende ser la propietaria de un asunto que no tiene propietario. Y que antes definía curiosidad como interés por saber lo que las cosas son y desde el 94 define curiosidad como interes por saber indiscretamente lo que las cosas son. Antes definia asombro como origen del conocimiento filosófico, y desde esa misma edición del 94, define asombro como susto espanto.\n  Ahí es donde está la mano del mediocre, que intenta recortarle a los demás la vida y decirles por donde tienen que ir. Negarse a que la realidad es proceso e insistir en que la realidad es definición y dogma\u0026rdquo; -Antonio Escohotado.\n Cierre #\r \u0026ldquo;Uno no puede dejar de asombrarse cuando contempla los misterios de la eternidad, de la vida, de la maravillosa estructura de la realidad. Es suficiente tratar de comprender un poquito de este misterio cada día; nunca perder esa sagrada curiosidad\u0026rdquo; -Albert Einstein.\n Si quieres saber más de las pinturas que aparecen en este artículo sigue este enlace.\n"}),e.add({id:2,href:"/blog/valor-de-una-promesa/",title:"Una película que te hará odiar al Estado",description:'\\"Ustedes lo encierran lo llenan de medicinas agujas y quien sabe que más lo maltratan y no hay discusión. Soy su padre. Tan solo quiero verlo decirle hola... y eso no.\\" Elmer Jackson, pidiendo ver a su hijo.',content:" \u0026ldquo;Ustedes lo encierran lo llenan de medicinas agujas y quien sabe que más lo maltratan y no hay discusión. Soy su padre. Tan solo quiero verlo decirle hola\u0026hellip; y eso no.\u0026rdquo; Elmer Jackson, pidiendo ver a su hijo.\n El Valor de una Promesa (After the Promise, en inglés) es una película basada en hechos reales que retrata con crudeza como un hombre y sus cuatro hijos pequeños son destruídos moral y físicamente, por parte de un sistema capaz de las más horribles vejaciones a la naturaleza humana.\nDurante 130 minutos seremos testigos de la persecución violenta que lideran burócratas del Estado en un intento por acabar con lo que queda de la familia Jackson, luego de que la madre muriese a causa de sus creencias religiosas que le impiden visitar al médico.\nAlgunos impulsados por la sevicia, otros escudados en la ley, trabajadores sociales, médicos, jueces y polícias pasan a convertirse en engranajes de una maquinaria inhumana capaz de separar, corromper, traumatizar y esterilizar a niños, de forma impune y en nombre de un supuesto bien común, que cómo no podría ser de otra forma, resulta ser el más retorcido capricho de aquellos al servicio del poder político.\n\u0026ldquo;Tu padre es tan solo un sujeto que vive de un martillo y clavos.\u0026rdquo;\nLa historia de Elmer Jackson, un humilde carpintero y sus hijos, es un conmovedor relato que estoy seguro no dejará a nadie indiferente, y que analizado desde la óptica de la lucha del ser humano por su libertad, en el más amplio de sus significados, es una película que retrata el verdadero talante del Estado: su naturaleza siempre violenta.\nPelícula completa #\rAquí está la cinta completa. La grabación tiene un audio de calidad regular, lamentablemente, pero no por ello se hace menos disfrutable la experiencia.\n  Algunas reflexiones adicionales #\rAntes de terminar, quisiera compartir un fragmento de una de las conversaciones de la película, en la que un Doctor discute sobre su obligación moral con el paciente, así como una frase de Gustave de Molinari a modo de conclusión de este breve artículo.\n  Tenemos una obligación moral hacia la comunidad en estos casos. Yo estoy seguro que estás de acuerdo conmigo\u0026hellip; No, no lo estoy. Y cuando se refiere el Doctor Prentice, creo que primero pienso en mi obligación moral hacia el paciente y no en la comunidad. No vamos a discutir sobre moral ahora. El Doctor Prentice sólo actúa de acuerdo a las políticas del Estado en estos asuntos. (\u0026hellip;) Richard Jackson se quedará aquí será esterilizado cuando llegue a la edad especificada aquí.    La ausencia de Estado \u0026ldquo;(\u0026hellip;) no es garantia de que algunas personas no matarán, lastimarán, secuestrarán, defraudarán, o robarán de otros. El gobierno es la garantía de que algunos lo harán\u0026rdquo; -Gustave de Molinari.\n "}),e.add({id:3,href:"/blog/disquetes-revistas/",title:"De los Disquetes y las Revistas de ordenadores",description:'\\"Sin dejarse llevar por el *torrentum* de productos, muchos de ellos de baja calidad, que invanden el mercado y que no hacen más que repetir los éxitos pasados, **las páginas de nuestra revista buscan**, ante todo y en lo posible, **lo novedoso**.\\" 1995, Editorial de la PC-Player Número 5.',content:" \u0026ldquo;Sin dejarse llevar por el torrentum de productos, muchos de ellos de baja calidad, que invanden el mercado y que no hacen más que repetir los éxitos pasados, las páginas de nuestra revista buscan, ante todo y en lo posible, lo novedoso.\u0026quot; 1995, Editorial de la PC-Player Número 5.\n Hoy viajaremos en el pasado hasta el cada vez más lejano, 1991. Internet era apenas un lugar oscuro y sumamente lento en el primer mundo, y en suramérica ni siquiera sabíamos de su existencia. Conseguir cualquier programa o juego era infinitamente más complicado.\nIndiana Jones y La última cruzada: La edición original traía varios cachivaches, incluído el diario de Henry Jones.\nPor su parte los originales, estaban fuera del alcance debido a sus precios exhorbitantes. Recuerdo estar muchas veces en los supermercados (de la ciudad más cercana al pueblo donde viviamos), con mi hermano mirando todas las cajas de juegos y soñando con algún día poder comprar aunque fuera uno de ellos.\nLa única opción real era que algún amigo, o un amigo de ese amigo, tuviera la gentileza de compartirte un disquete pirata (de dudosa procedencia) con algún que otro programa y, preferiblemente, un puñado de juegos. Las calidades variaban, de repente te tocaba un juego que se convertiría en un clásico de culto o quizá uno que sería olvidado a la vuelta de la esquina. Pero la dificultad para conseguirlos, el aspecto físico propio del disquete todos sus entresijos y mecanismos, el compartir y el inherente riesgo a terminar con un virus o que el disco físico estuviese dañado, creaban un aura especial.\nPrince of Persia: Clásico entre clásicos. Conocido en nuestros países gracias a la piratería.\nY para nosotros las cosas siguieron así, hasta una noche de 1996. Aún recuerdo con especial nitidez que recibimos de manos de nuestro padre una extraña revista. No es un regalo al que estuvieramos acostumbrados de niños. Sin embargo, esta revista era diferente a todas las demás, era una revista de juegos para PC, de hecho era la PC-Player número 5. Cargadas de discos con demos (usualmente uno o dos niveles de un juego), shareware (generalmente contenían el primer episodio de un juego) y a veces juegos completos, pasaron a llenar nuestra infancia de momentos inolvidables*.\nMystic Towers: una experiencia oscura que nunca pudimos terminar, pero que siempre alimentó nuestra imaginación.\nPodíamos pasar horas jugando, leyendo e imaginando. En especial imaginando porque los juegos que no estaban completos, o que no estaban presentes en los discos (aquellos que sólo salían en los reportajes impresos de la revista), permitián a la mente volar, fantaseando con explorar aquellos niveles llenos de colores y personajes pintorescos.\nLa insistencia de mi padre a encontrar estas publicaciones (que eran escasas y sólo vendían en un par de sitios alejados) permitió que jugase junto con mi hermano, aunque fuera de forma parcial, a miles de títulos, que de otra forma hubiesen escapado de nuestro alcance. Pero también, que pudiesemos tener nuestros primeros acercamientos con la curiosidad y el asombro, con la alegría del descubrir: a veces nos sentábamos a explorar los recovecos más extraños de los discos, y en varias ocaciones fuimos recompenzados con juegos ocultos, que por error no aparecián en los índices de las revistas, ni en los menús de sus discos.\nDiscworld (Mundodisco): que lo encontró mi hermano en un disco curioso como ninguno. Digna coincidencia de la saga de Terry Pratchet.\nEsas revistas eran como publicaciones cuasi-mágicas, hechas por personas apasionadas que compartían sus experiencias y descubrimientos en ese mundillo incipiente del entretenimiento digital. Claro está, esas revistas desaparecieron con el tiempo, pero para quiénes tuvimos el placer de explorarlas, vivirán por siempre en nuestra memoria.\nIshar 2, uno de los viajes más difíciles pero gratificantes en aquel entonces.\nApéndice #\rPara quiénes les interese, aquí comparto la PC-Player número 5 y algunos videos de las demos que contenia.\nSimon the Sorcerer 2 #\rDemo #\r   Por si te interesa, Aquí el gameplay completo.  Braindead 13 #\rDemo #\rEl video se ve muy pequeño, pero la calidad de animación es excelente.    Por si te interesa, aquí el gameplay completo.  Prisoner of Ice demo #\rDemo #\r   Por si te interesa, aquí el gameplay completo.  Ultimate Soccer Manager #\r  "}),e.add({id:4,href:"/blog/mundodisco-tipos-personas/",title:"A quiénes pertenece el mundo y otros tipos de personas",description:'"A William de Worde, editor accidental del primer periódico del Mundodisco, siempre le ha preocupado la naturaleza de la verdad. Sabe que se esconde en lugares improbables y cuenta con sirvientes extraños." La Verdad, XXV novela del Mundodisco.',content:" \u0026ldquo;A William de Worde, editor accidental del primer periódico del Mundodisco, siempre le ha preocupado la naturaleza de la verdad. Sabe que se esconde en lugares improbables y cuenta con sirvientes extraños.\u0026rdquo; La Verdad, XXV novela del Mundodisco.\n Uno pensaría encontrar sabiduría en elegantes manuscritos ancestrales, no en una novela escrita en clave de humor, mucho menos una en la que el mundo es plano y está sostenido por elefantes que viajan encima de una tortuga gigante a través del espacio. Sin embargo, quién decida entrar en las páginas inmortales del Mundodisco y salga de allí sin cambiar de opinión, sólo podría catalogarse como un necio irreparable.\nMundodisco es una saga de novelas creada por Terry Pratchet, una obra única en su estilo que combina de forma excelsa lo cómico y lo filosófico, lo mágico y científico, lo mundano y lo transcendental del ser humano. Un continuo conflicto que suele difuminar la linea entre la burla y la crítica, retratando entre líneas la dualidad de la naturaleza humana: una frágil existencia empujada por ambiciones desmedidas (usualmente ridículas para un ser tan fútil).\nDicho esto, mientras leía el libro La Verdad, la XXV novela del Mundodisco, me topé con algunas inusitadas lecciones de sabiduría que me he sentido obligado a compartir con ustedes. Éste es el fragmento:\n Se dice que hay dos tipos de personas en el mundo. Están aquellos que, cuando se les presenta un vaso que está exactamente medio lleno, dicen: este vaso está medio lleno. Y están aquellos que dicen: este vaso está medio vacío.\n  El mundo pertenece, sin embargo, a aquellos que pueden mirar el vaso y decir: «¿Qué le pasa a este vaso? ¿Perdone? ¡Perdone! ¿Este es mi vaso? Me parece a mí que no. ¡Mi vaso estaba lleno! ¡Y era un vaso más grande!» .\n  Y en el otro extremo de la barra, el mundo está lleno del otro tipo de personas, las que tienen el vaso roto, o un vaso derribado por descuido (habitualmente por una de las personas que piden un vaso más grande), o las que ni siquiera tienen vaso, porque estaban al fondo de la muchedumbre y no han conseguido llamar la atención del barman.\n "}),e.add({id:5,href:"/docs/espanol/",title:"Español",description:"Sobre el idioma",content:""}),e.add({id:6,href:"/docs/intro/intro/",title:"Introducción",description:"Nuestra colección de contenidos extraños.",content:" Incluso en aquellos malos tiempos para las criaturas mágicas, incluso en una habitación diseñada para amortiguar todas las vibraciones de la hechicería, el Octavo seguía crepitando con su energía.\n  En realidad, las antorchas no hacían la menor falta. El Octavo llenaba la habitación de una luz tenue, mortecina, que no era exactamente luz sino lo contrario de la luz. La oscuridad no es lo contrario de la luz, sino su ausencia. Lo que irradiaba del libro era la luz que yace al otro lado de la oscuridad. La luz fantástica. Era de un color púrpura bastante decepcionante.\n "}),e.add({id:7,href:"/docs/arte/pinturas/",title:"Pinturas",description:"Arte que aparece en El Acantilado.",content:"Portada #\r Иван К. Айвазовский - От Млеты до Гудаури (1868) Ivan K. Aivazovsky - De Mleta a Gudauri (1868) Imagen  Sobre el asombro y la curiosidad #\r Petrov-Vodkin. Fantasy. Imagen   Иван К. Айвазовский - Неаполитанский залив (1845) Ivan K. Aivazovsky - Bahía de Nápoles (1845) Imagen  "}),e.add({id:8,href:"/docs/espanol/palabras/",title:"Diccionario de rarezas",description:"Algunas sofisticadas otras en desuso, pero todas palabras curiosas del idioma español.",content:" \u0026ldquo;Las palabras se parecen a peces en el hecho de que algunos que se especializan pueden sobrevivir solamente en un tipo determinado de arrecifes, donde sus curiosas formas y usos quedan protegidos del bullicio de alta mar. «Trifulca» y «altercado» solamente se encuentran en ciertos periódicos (de la misma manera que la palabra «refrigerios» solamente se encuentra en ciertos menús). Nunca se usan en la conversación normal.\u0026rdquo; -Terry Pratchet. La Verdad, XXV novela del Mundodisco.\n Clasificación #\rPalabras marcadas con * (asteriscos) indica que son raras. A más asteriscos más raras. Las demás quizá no sean rarísimas pero no son de uso común.\nListado #\rAcrecentar #\rMejorar, enriquecer, enaltecer.\nAcodar * #\r Apoyar el codo sobre alguna parte, por lo común para sostener con la mano la cabeza. Doblar algo en forma de codo.  Acrópolis ** #\rRecinto fortificado en la parte más alta de las antiguas ciudades griegas.\nAfín #\rParecido, similar.\nAlevín *** #\r Cría de pez. Joven principiante que se inicia en una disciplina o profesión.  Alforja * #\rProvisión de los comestibles necesarios para el camino.\nAlmadía ** #\rEmbarcación formada por troncos o maderos unidos.\nAmoladera *** #\rAsperón: Arenisca de cemento silíceo o arcilloso, que se emplea en los usos generales de construcción y también, cuando es de grano fino y uniforme, en piedras de amolar y para usos de limpieza doméstica.\nAnálogo #\rQue tiene analogía o similitud con una cosa.\nApiñar * #\rJuntar o agrupar estrechamente personas o cosas.\nApremiante #\rQue apremia.\nAprensión #\r Cuidado que una persona tiene de no cometer abusos o faltas de consideración. SINÓNIMO: escrúpulo Recelo de ponerse una persona en contacto con otra o con una cosa que pueda ser perjudicial o peligrosa para él. EJEMPLO: los leprosos no le daban ninguna aprensión.  Asidero * #\r Parte por donde se ase algo. Ocasión o pretexto.  Arracimar * #\rUnirse o juntarse en forma de racimo.\nAtildado * #\rPulcro, elegante.\nAtisbar * #\rMirar, observar con cuidado, recatadamente.\nAtónito #\rPasmado, absorto.\nAterir ** #\rPasmar de frío\nAtolón * #\rUn atolón es una isla coralina oceánica, por lo general con forma de anillo más o menos circular, o también se entiende como el conjunto de varias islas pequeñas que forman parte de un arrecife de coral, con una laguna interior que comunica generalmente con el mar.\nAtracón * #\r Exceso en una actividad cualquiera. Altercado, riña.  Aunar #\rUnir, armonizar o poner de acuerdo cosas o personas distintas para contribuir a una causa común o para conseguir un fin determinado.\nAupar * #\rLevantar o subir algo o a alguien con los brazos. Conceder grandeza, honor o más valor a una persona o cosa.\nAutarquía #\rDel gr. αὐταρχία autarchía \u0026lsquo;poder absoluto\u0026rsquo;. Dominio de sí mismo. Autosuficiencia. Política de un Estado que intenta bastarse con sus propios recursos.\nAversión #\rRechazo o repugnancia frente a alguien o algo.\nBauprés *** #\rPalo grueso, horizontal o algo inclinado, que en la proa de los barcos sirve para asegurar los estayes del trinquete.\nBergantín ** #\rBuque de dos palos y vela cuadrada o redonda.\nBlandir #\rMover con la mano algo, especialmente un arma, con movimiento trémulo o vibratorio.\nCadalso ** #\rTablado para una ejecución o acto solemne.\nCamastro * #\rLecho pobre y sin aliño.\nCanapé ** #\r Mueble para sentarse o recostarse, en forma de banco, con el asiento y el respaldo acolchados. Porción de pan o de hojaldre cubierta con una pequeña cantidad de comida que se suele servir como aperitivo.  Capitel *** #\rParte superior de una columna.\nCarillón *** #\rGrupo de campanas en una torre, que producen un sonido armónico por estar acordadas.\nCazo ** #\rRecipiente de cocina.\nCazoleta ** #\rReceptáculo pequeño que llevan algunos objetos, como el palo del boliche, el depósito del tabaco en la pipa o el narguile, etc.\nCéfiro *** #\r Viento del oeste. Tela de algodón casi transparente y de colores variados.  Ciclópea *** #\rDicho de ciertas construcciones antiquísimas que se distinguen por el enorme tamaño de sus piedras, unidas por lo común sin argamasa.\nCrepitar * #\rProducir sonidos repetidos, rápidos y secos, como el de la sal en el fuego.\nCrispar #\r Causar contracción repentina y pasajera en el tejido muscular. Irritar o exasperar a alguien.  Denuedo ** #\rBrío, intrepidez.\nDesacompasado ** #\rReferido a persona o cosa, descomedida, desproporcionada.\nDesmadejado ** #\rDicho de una persona: Que se siente con flojedad o quebrantamiento en el cuerpo.\nDesiderátum *** #\rDeseo o aspiración que aún no se ha cumplido.\nDesván #\rParte más alta de la casa, situada inmediatamente debajo del tejado y carente de falso techo, que se destina especialmente a guardar objetos en desuso.\nDesvencijadas #\rAflojar, desunir y desconcertar las partes de algo que estaban y debían estar unidas.\nDesconcertante #\rQue produce desconcierto o perplejidad.\nDiscurría #\r Pensar o imaginar algo. Moverse avanzando por un lugar. Dicho del tiempo o de un acontecimiento: Transcurrir o avanzar en su desarrollo.  Efluvio *** #\rEmisión de partículas sutilísimas.\nEjote *** #\rVaina del frijol cuando está tierna.\nElucubrar ** #\rElaborar una divagación complicada\nEmboscadura * #\r Acción de emboscar o emboscarse. Lugar que sirve para emboscar o emboscarse.  Entornar * #\r Volver la puerta o la ventana sin cerrarla del todo. Cerrar los ojos de manera incompleta. Inclinar, ladear, trastornar.  Escarpadas * #\rDicho de una altura: Que no tiene subida ni bajada transitable o la tiene muy áspera y peligrosa.\nEscudriñar #\rExaminar, inquirir y averiguar cuidadosamente algo y sus circunstancias.\nEspetar * #\r Atravesar con el asador, u otro instrumento puntiagudo, carne, aves, pescados, etc., para asarlos. Decir a alguien de palabra o por escrito algo, causándole sorpresa o molestia. Me espetó una arenga, un cuento, una carta.  Espigón ** #\r Punta del palo con que se aguija. Macizo saliente que se construye a la orilla de un río o en la costa del mar, para defender las márgenes o modificar la corriente. Columna que forma el eje de una escalera de caracol.  Esteta *** #\rPersona que considera el arte como valor esencial.\nEstólido * #\rFalto de razón y discurso.\nEstrépito #\rRuido considerable.\nExecración ** #\rPerdida del carácter sagrado de un lugar\nFardo *** #\rLío grande de ropa u otra cosa, apretado para poder llevarlo de una parte a otra.\nFulcro *** #\rPunto de apoyo de la palanca.\nGalimatías *** #\rLenguaje oscuro por la confusión de ideas\nHendidura * #\rCorte en una superficie o en un cuerpo sólido cuando no llega a dividirlos del todo.\nHorcajadas * #\rA horcajadas. Dicho de montar, cabalgar o sentarse: Con una pierna a cada lado de la caballería, persona o cosa sobre la que se está.\nIgnoto *** #\rQue no se conoce o no ha sido descubierto. \u0026ldquo;nos resultan incomprensibles y lejanos los ignotos motivos que desencadenaron la matanza\u0026rdquo;\nImpeler * #\rImpulsar.\nImpasible #\r Incapaz de padecer o sentir. Indiferente, imperturbable.  Indeleble #\rQue no se puede borrar o quitar.\nIniquidad *** #\rInjusticia o gran maldad en el modo de obrar.\nIntentona * #\rIntento temerario, especialmente si se ha frustrado.\nIridiscente * #\rQue muestra o refleja los colores del arco iris.\nJamba *** #\rLados que sostienen el dintel de una puerta.\nLacustre * #\rRelativo a los lagos\nLisonjear *** #\rDeleitar, agradar.\nLóbrego ** #\rOscuro, tenebroso. Triste melancólico.\nMacilento *** #\rFlaco y descolorido.\nMácula ** #\rMancha, engaño.\nMitógrafo *** #\rLa mitografía es el estudio de mitos y leyendas antiguas que conforman las mitologías; podría decirse que un mitógrafo es un «coleccionista de mitos».\nMustio ** #\rMelancólico, triste\nOblongo * #\rMás largo que ancho.\nOminoso * #\rAbominable, despreciable.\nPaladear *** #\rTomar poco a poco el gusto de algo.\nPalmatoria *** #\rEspecie de candelero bajo, con mango y pie, generalmente de forma de platillo.\nPanegírico *** #\rDiscurso en el que se alaba a alguien, especialmente el que se hace en honor a un santo. \u0026ldquo;en el siglo IV la literatura hispanocristiana contó con cultivadores ilustres, como el papa san Dámaso, autor de panegíricos de santos y mártires\u0026rdquo;\nParrafada ** #\r Conversación detenida y confidencial. Trozo largo y pesado de charla o conversación.  Pendía #\r Estar colgada, suspendida o inclinada. Estar subordinado a alguien o algo.  Perorata * #\rDiscurso pesado y sin sustancia\nPerneras ** #\rParte del calzón o pantalón que cubre cada pierna.\nPétreo #\rDe piedra\nPlúmbeo * #\r De plomo. Muy aburrido o pesado.  Porteador * #\rQue Conduce o lleva algo de una parte a otra por el porte o precio convenido o señalado.\nProeza #\rAcción de gran esfuerzo y valor.\nProfiláctico ** #\rQue sirve para preservar o proteger de una enfermedad o un mal.\nProsaico * #\rVulgar. Que no tiene gracia o ingenio.\nRaudo * #\rRápido, violento, precipitado.\nReluctancia ** #\rResistencia que ofrece un circuito al flujo magnético.\nRenuencia #\rResistencia que se muestra a hacer algo.\nResolló * #\rRespirar haciendo ruido o de forma entrecortada.\nReticencia #\rReserva, desconfianza.\nRezumar * #\rDejar pasar a través de sus poros o rendijas.\nSabañón ** #\rHinchazón o ulceración de la piel, principalmente de las manos, los pies y las orejas, que es causada por frío excesivo y produce ardor y picazón.\nSátira #\rLa sátira es el arte de hacerle ridículo a alguien o algo, provocando la risa para avergonzar, humillar o desacreditarlo.\nSempiterno #\rQue durará siempre, que no tendrá fin. \u0026ldquo;vida sempiterna\u0026rdquo;.\nSendos *** #\rEstablece una relación de uno a uno entre los miembros de un conjunto de dos o más cosas o personas y los de otro conjunto de cosas o personas denotadas por el nombre al cual acompaña. ambas películas están basadas en sendos relatos de Terry Pratchet.\nSima *** #\rCavidad grande y muy profunda en la tierra.\nSolaz *** #\rEsparcimiento.\nSolícito #\rDiligente, cuidadoso.\nTenue #\rDelicado, delgado y débil.\nTeosofía *** #\rDenominación que se da a diversas doctrinas religiosas y místicas, que creen estar iluminadas por la divinidad e íntimamente unidas con ella.\nTerraplén *** #\rMacizo de tierra con que se rellena un hueco, o que se levanta para hacer una defensa, un camino u otra obra semejante.\nTitubear #\r Oscilar, perdiendo la estabilidad y firmeza. Tropezar o vacilar en la elección o pronunciación de las palabras. Sentir perplejidad en algún punto o materia.  Trémulo * #\rQue tiembla. Voz trémula\nVolición *** #\rVolición es, en un sentido general, un acto de la voluntad o una acción voluntaria.​ Lo volitivo es lo relativo a la volición o voluntad.\nVetusto * #\rViejo.\nZozobrante * #\r Dicho de una embarcación: Peligrar por la fuerza y contraste de los vientos. Perderse o irse a pique. Estar inquieto o desazonado por la inseguridad respecto de algo o por la incertidumbre sobre lo que conviene hacer.  "}),e.add({id:9,href:"/docs/espanol/para-escribir/",title:"Para escribir",description:"Algunas ideas, palabras o frases para cuando se escribe.",content:"Combinaciones de palabras #\r  Hurgarse la nariz industriosamente\n  Entornando los ojos.\n  Un atisbo de esperanza.\n  Se me antoja anticuado.\n  Observar con aprensión.\n  Se irguió / se dejó caer.\n  Frunció el ceño.\n  Jardines yermos.\n  Advirtió algo extraño.\n  Cuando se escriben diálogos #\r  Espetó\n  Exclamó\n  Replicó\n  Musitó\n  Respondió vagamente\n  Murmuro\n  Sugirió\n  Inquirió\n  Exigió\n  Respondió\n  Explicó\n  Aprobó\n  Carraspeó\n  Parloteó\n  Suspiró\n  Sollozó\n  Interpeló\n  Escudriñó.\n  "}),e.add({id:10,href:"/docs/arte/",title:"Arte",description:"Arte",content:""}),e.add({id:11,href:"/blog/",title:"Blog",description:"The Doks Blog.",content:""}),e.add({id:12,href:"/docs/",title:"Docs",description:"Docs Doks.",content:""}),search.addEventListener("input",t,!0);function t(){const s=5;var n=this.value,o=e.search(n,{limit:s,enrich:!0});const t=new Map;for(const e of o.flatMap(e=>e.result)){if(t.has(e.doc.href))continue;t.set(e.doc.href,e.doc)}if(suggestions.innerHTML="",suggestions.classList.remove("d-none"),t.size===0&&n){const e=document.createElement("div");e.innerHTML=`No results for "<strong>${n}</strong>"`,e.classList.add("suggestion__no-results"),suggestions.appendChild(e);return}for(const[r,a]of t){const n=document.createElement("div");suggestions.appendChild(n);const e=document.createElement("a");e.href=r,n.appendChild(e);const o=document.createElement("span");o.textContent=a.title,o.classList.add("suggestion__title"),e.appendChild(o);const i=document.createElement("span");if(i.textContent=a.description,i.classList.add("suggestion__description"),e.appendChild(i),suggestions.appendChild(n),suggestions.childElementCount==s)break}}})()